function createEmitter() {
  const events = {};
  return {
    on(event, fn) {
      if (!events[event]) events[event] = [];
      events[event].push(fn);
    },
    emit(event, ...args) {
      if (events[event]) events[event].forEach(fn => fn(...args));
    }
  };
}
