solution.code:
function myReduce(arr, fn, initial) {
  let acc = initial;
  let startIdx = 0;
  if (acc === undefined) {
    acc = arr[0];
    startIdx = 1;
  }
  for (let i = startIdx; i < arr.length; i++) {
    acc = fn(acc, arr[i], i, arr);
  }
  return acc;
}
console.log(myReduce([1, 2, 3, 4], (acc, val) => acc + val, 0));

