function fibIterator(limit) {
  return {
    [Symbol.iterator]() {
      let a = 0, b = 1;
      return {
        next() {
          const value = b;
          if (value > limit) return { done: true };
          [a, b] = [b, a + b];
          return { value, done: false };
        }
      };
    }
  };
}
console.log([...fibIterator(10)].join(","));

