solution.code:
function dfsPath(graph, start, end) {
  const visited = new Set();
  function dfs(node, path) {
    if (node === end) return [...path, node];
    visited.add(node);
    for (const neighbor of (graph[node] || [])) {
      if (!visited.has(neighbor)) {
        const result = dfs(neighbor, [...path, node]);
        if (result) return result;
      }
    }
    return null;
  }
  return dfs(start, []);
}
console.log(dfsPath({ A: ["B", "C"], B: ["D"], C: [], D: ["E"], E: [] }, "A", "E").join(","));

